import { render, screen } from '@testing-library/react'
import { describe, it, expect, vi, beforeEach } from 'vitest'
import React from 'react'

// ─── Mocks ────────────────────────────────────────────────────────────────────

vi.mock('@/lib/algolia', () => ({
  algoliaClient: {},
  CARDS_INDEX: 'test_cards',
  CARDS_INDEX_PRICE_ASC: 'test_cards_price_asc',
  CARDS_INDEX_PRICE_DESC: 'test_cards_price_desc',
}))

// Mock InstantSearchNext to just render children (no real Algolia)
