import { algoliaClient, CARDS_INDEX } from "@/lib/algolia"
import { createCardsStateMapping } from "./AlgoliaSearchResults"
import { CardSearchGrid } from "./CardSearchGrid"
import { ActiveFilterChips } from "./ActiveFilterChips"
import { SortControl } from "./SortControl"
import Link from "next/link"

// ─── Search Breadcrumbs ────────────────────────────────────────────────────────

function SearchBreadcrumbs({ query }: { query: string }) {
  return (
    <div
      data-testid="search-breadcrumbs"
      style={{
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        padding: "12px 32px",
        background: "var(--bg-surface-1, #18162A)",
        borderBottom: "1px solid var(--border-default, #2C2A4A)",
        flexWrap: "wrap",
        gap: 8,
      }}
    >
      <nav
        aria-label="Breadcrumb"
        style={{
          display: "flex",
          alignItems: "center",
          gap: 6,
          fontSize: 12,
          color: "var(--text-tertiary, #7B72A8)",
        }}
      >
        <Link
          href="/"
          style={{
            color: "var(--text-tertiary, #7B72A8)",
            textDecoration: "none",
          }}
        >
          Home
        </Link>
        <span style={{ color: "var(--border-strong, #4A4680)" }}>›</span>
        <Link
          href="/search"
          style={{
            color: "var(--text-tertiary, #7B72A8)",
            textDecoration: "none",
          }}
        >
          Search Results
        </Link>
        {query && (
          <>
            <span style={{ color: "var(--border-strong, #4A4680)" }}>›</span>
            <span
              style={{
                color: "var(--text-primary, #F0EEFF)",
                fontWeight: 500,
              }}
            >
              &ldquo;{query}&rdquo;
            </span>
          </>
        )}
      </nav>
    </div>
  )
}

// ─── Results Header ────────────────────────────────────────────────────────────

function SearchResultsHeader() {
  const { nbHits, query } = useStats()

  return (
    <div
      data-testid="search-results-header"
      style={{
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        padding: "14px 32px",
        background: "var(--bg-base, #0F0E1A)",
        borderBottom: "1px solid var(--border-default, #2C2A4A)",
      }}
    >
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: 12,
          flexWrap: "wrap",
          flex: 1,
          minWidth: 0,
        }}
      >
        {/* Result count + query */}
        <div
          style={{
            fontSize: 13,
            color: "var(--text-secondary, #B8B0D8)",
          }}
        >
          {query ? (
            <>
              <span
                style={{
                  fontWeight: 600,
                  color: "var(--text-primary, #F0EEFF)",
                }}
              >
                {nbHits.toLocaleString()}
              </span>{" "}
              results for &ldquo;{query}&rdquo;
            </>
          ) : (
            "Search SideDecked"
          )}
        </div>

        {/* Active filter chips inline */}
        <div style={{ flex: 1, minWidth: 0 }}>
          <ActiveFilterChips />
        </div>
      </div>

      {/* Sort control — desktop only */}
      <div className="hidden md:block" style={{ flexShrink: 0, marginLeft: "auto" }}>
        <SortControl />
      </div>
    </div>
  )
}

// ─── Inner Content (needs InstantSearch context) ───────────────────────────────

function SearchPageContent({ query }: { query: string }) {
  return (
    <div>
      {/* Breadcrumbs: Home > Search Results > "query" */}
      <SearchBreadcrumbs query={query} />

      {/* Results header with count, filter chips, sort */}
      <SearchResultsHeader />

      {/* Shared sidebar + grid layout */}
      <CardSearchGrid />
    </div>
  )
}

// ─── Public component ─────────────────────────────────────────────────────────

interface SearchPageLayoutProps {
  query: string
}

export function SearchPageLayout({ query }: SearchPageLayoutProps) {
  return (
    <InstantSearchNext
      searchClient={algoliaClient}
      indexName={CARDS_INDEX}
      routing={{ stateMapping: createCardsStateMapping() }}
      initialUiState={{
        [CARDS_INDEX]: {
          query,
          refinementList: {
            game: [],
            rarity: [],
            condition: [],
            set_name: [],
            language: [],
          },
        },
      }}
    >
      <Configure hitsPerPage={20} />
      <SearchPageContent query={query} />
    </InstantSearchNext>
  )
}

import { SearchPageLayout } from "@/components/search/SearchPageLayout"

interface SearchPageProps {
  searchParams: Promise<{ q?: string }>
}

export default async function SearchPage({ searchParams }: SearchPageProps) {
  const params = await searchParams
  const query = params.q ?? ""

